import{_ as a,c as o,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Interrupção de Streaming: Solução de 0 Token | Antigravity-Manager","description":"Aprenda o caminho de solução para interrupção de streaming, 0 Token e assinatura inválida do Antigravity Tools. Confirme /v1/messages ou chamada de streaming nativo Gemini, entenda peek pré-leitura e backoff retry, combine com Proxy Monitor e logs para localizar rapidamente a causa e determinar se precisa rolar contas.","frontmatter":{"title":"Interrupção de Streaming: Solução de 0 Token | Antigravity-Manager","sidebarTitle":"Autocura ou Intervenção Manual","subtitle":"Interrupção de Streaming/0 Token/Assinatura Inválida: Mecanismo de Autocura e Caminho de Solução","description":"Aprenda o caminho de solução para interrupção de streaming, 0 Token e assinatura inválida do Antigravity Tools. Confirme /v1/messages ou chamada de streaming nativo Gemini, entenda peek pré-leitura e backoff retry, combine com Proxy Monitor e logs para localizar rapidamente a causa e determinar se precisa rolar contas.","tags":["faq","streaming","troubleshooting","retry"],"prerequisite":["start-getting-started","start-first-run-data","advanced-monitoring","advanced-scheduling"],"order":5},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/faq/streaming-0token/index.md"};function s(d,e,n,c,l,u){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="interrupcao-de-streaming-0-token-assinatura-invalida-mecanismo-de-autocura-e-caminho-de-solucao" tabindex="-1">Interrupção de Streaming/0 Token/Assinatura Inválida: Mecanismo de Autocura e Caminho de Solução <a class="header-anchor" href="#interrupcao-de-streaming-0-token-assinatura-invalida-mecanismo-de-autocura-e-caminho-de-solucao" aria-label="Permalink to &quot;Interrupção de Streaming/0 Token/Assinatura Inválida: Mecanismo de Autocura e Caminho de Solução&quot;">​</a></h1><p>Ao chamar <code>/v1/messages</code> (compatível com Anthropic) ou a interface de streaming nativo do Gemini no Antigravity Tools, se você encontrar problemas como &quot;saída de streaming interrompida&quot;, &quot;200 OK mas 0 Token&quot;, &quot;Invalid <code>signature</code>&quot;, este curso fornece um caminho de solução da UI aos logs.</p><h2 id="o-que-voce-podera-fazer-apos-este-curso" tabindex="-1">O Que Você Poderá Fazer Após Este Curso <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-este-curso" aria-label="Permalink to &quot;O Que Você Poderá Fazer Após Este Curso&quot;">​</a></h2><ul><li>Saber que problemas de 0 Token/interrupção no proxy geralmente serão bloqueados primeiro pelo &quot;peek pré-leitura&quot;</li><li>Poder confirmar a conta e modelo mapeado desta solicitação no Proxy Monitor (<code>X-Account-Email</code> / <code>X-Mapped-Model</code>)</li><li>Poder determinar através de logs se é &quot;fluxo upstream morreu cedo&quot;, &quot;backoff retry&quot;, &quot;rotação de conta&quot; ou &quot;retry de reparo de assinatura&quot;</li><li>Saber quais situações esperar a autocura do proxy, quais situações exigir intervenção manual</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p>Você pode ver esses &quot;fenômenos&quot;, mas não sabe por onde começar:</p><ul><li>A saída de streaming para pela metade, o cliente parece &quot;travado&quot; e não continua</li><li>200 OK, mas <code>usage.output_tokens=0</code> ou conteúdo vazio</li><li>Erro 400 aparece <code>Invalid \\</code>signature`<code>, </code>Corrupted thought signature<code>, </code>must be `thinking`` etc.</li></ul><p>Esses problemas geralmente não são &quot;você escreveu a solicitação errada&quot;, mas streaming, limitação upstream/flutuação, ou blocos de assinatura em mensagens históricas que dispararam a verificação upstream. O Antigravity Tools fez múltiplas linhas de defesa na camada de proxy, você só precisa verificar em qual passo parou por um caminho fixo.</p><h2 id="o-que-e-0-token" tabindex="-1">O Que é 0 Token? <a class="header-anchor" href="#o-que-e-0-token" aria-label="Permalink to &quot;O Que é 0 Token?&quot;">​</a></h2><p><strong>0 Token</strong> geralmente se refere a <code>output_tokens=0</code> retornado por uma solicitação, e parece &quot;não gerou conteúdo&quot;. No Antigravity Tools, sua causa mais comum é &quot;resposta de streaming termina/erro antes de realmente produzir saída&quot;, não o modelo realmente gerou 0 tokens. O proxy tentará usar peek pré-leitura para bloquear tais respostas vazias e disparar retry.</p><h2 id="tres-coisas-que-o-proxy-faz-nos-bastidores-primeiro-tenha-um-modelo-mental" tabindex="-1">Três Coisas que o Proxy Faz nos Bastidores (Primeiro Tenha um Modelo Mental) <a class="header-anchor" href="#tres-coisas-que-o-proxy-faz-nos-bastidores-primeiro-tenha-um-modelo-mental" aria-label="Permalink to &quot;Três Coisas que o Proxy Faz nos Bastidores (Primeiro Tenha um Modelo Mental)&quot;">​</a></h2><h3 id="_1-solicitacoes-nao-streaming-podem-ser-automaticamente-convertidas-em-streaming" tabindex="-1">1) Solicitações Não Streaming Podem Ser Automaticamente Convertidas em Streaming <a class="header-anchor" href="#_1-solicitacoes-nao-streaming-podem-ser-automaticamente-convertidas-em-streaming" aria-label="Permalink to &quot;1) Solicitações Não Streaming Podem Ser Automaticamente Convertidas em Streaming&quot;">​</a></h3><p>No caminho <code>/v1/messages</code>, o proxy internamente converterá &quot;solicitações não streaming do cliente&quot; em solicitações de streaming para solicitar upstream, e após receber SSE coletará em JSON para retornar (a razão está escrita nos logs como &quot;better quota&quot;).</p><p>Evidência do código-fonte: <code>src-tauri/src/proxy/handlers/claude.rs#L665-L913</code>.</p><h3 id="_2-peek-pre-leitura-aguarde-primeiro-bloco-de-dados-valido-antes-de-entregar-o-fluxo-ao-cliente" tabindex="-1">2) Peek Pré-leitura: Aguarde &quot;Primeiro Bloco de Dados Válido&quot; Antes de Entregar o Fluxo ao Cliente <a class="header-anchor" href="#_2-peek-pre-leitura-aguarde-primeiro-bloco-de-dados-valido-antes-de-entregar-o-fluxo-ao-cliente" aria-label="Permalink to &quot;2) Peek Pré-leitura: Aguarde &quot;Primeiro Bloco de Dados Válido&quot; Antes de Entregar o Fluxo ao Cliente&quot;">​</a></h3><p>Para saída SSE de <code>/v1/messages</code>, o proxy primeiro fará <code>timeout + next()</code> pré-leitura, pulando linhas de heartbeat/comentários (começando com <code>:</code>), até pegar o primeiro bloco de dados &quot;não vazio, não heartbeat&quot; antes de começar o encaminhamento oficial. Se peek relatar erro/timeout/fluxo terminar, entrará diretamente na próxima tentativa (a próxima tentativa geralmente disparará rotação de conta).</p><p>Evidência do código-fonte: <code>src-tauri/src/proxy/handlers/claude.rs#L812-L926</code>; Streaming nativo Gemini também tem peek similar: <code>src-tauri/src/proxy/handlers/gemini.rs#L117-L149</code>.</p><h3 id="_3-backoff-retry-unificado-decidir-rolar-conta-ou-nao-por-codigo-de-status" tabindex="-1">3) Backoff Retry Unificado + Decidir &quot;Rolar Conta ou Não&quot; Por Código de Status <a class="header-anchor" href="#_3-backoff-retry-unificado-decidir-rolar-conta-ou-nao-por-codigo-de-status" aria-label="Permalink to &quot;3) Backoff Retry Unificado + Decidir &quot;Rolar Conta ou Não&quot; Por Código de Status&quot;">​</a></h3><p>O proxy fez estratégias de backoff explícitas para códigos de status comuns, e definiu quais códigos de status dispararão rotação de conta.</p><p>Evidência do código-fonte: <code>src-tauri/src/proxy/handlers/claude.rs#L117-L236</code>.</p><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação Antes de Começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação Antes de Começar&quot;">​</a></h2><ul><li>Você pode abrir o Proxy Monitor (veja <a href="./../../advanced/monitoring/">Proxy Monitor: Logs de Solicitação, Filtro, Restauração de Detalhes e Exportação</a>)</li><li>Você sabe que logs estão em <code>logs/</code> no diretório de dados (veja <a href="./../../start/first-run-data/">Primeira Inicialização: Diretório de Dados, Logs, Bandeja e Inicialização Automática</a>)</li></ul><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-confirme-qual-caminho-de-interface-voce-esta-chamando" tabindex="-1">Passo 1: Confirme Qual Caminho de Interface Você Está Chamando <a class="header-anchor" href="#passo-1-confirme-qual-caminho-de-interface-voce-esta-chamando" aria-label="Permalink to &quot;Passo 1: Confirme Qual Caminho de Interface Você Está Chamando&quot;">​</a></h3><p><strong>Por Que</strong> Os detalhes de autocura de <code>/v1/messages</code> (claude handler) e Gemini nativo (gemini handler) são diferentes, primeiro confirmar o caminho evita desperdiçar tempo nas palavras-chave erradas de log.</p><p>Abra o Proxy Monitor, encontre aquela solicitação falhada, primeiro anote o Path:</p><ul><li><code>/v1/messages</code>: veja a lógica de <code>src-tauri/src/proxy/handlers/claude.rs</code></li><li><code>/v1beta/models/...:streamGenerateContent</code>: veja a lógica de <code>src-tauri/src/proxy/handlers/gemini.rs</code></li></ul><p><strong>Você Deve Ver</strong>: No registro de solicitação você pode ver URL/método/código de status (e tempo gasto da solicitação).</p><h3 id="passo-2-pegue-conta-modelo-mapeado-do-header-de-resposta" tabindex="-1">Passo 2: Pegue &quot;Conta + Modelo Mapeado&quot; do Header de Resposta <a class="header-anchor" href="#passo-2-pegue-conta-modelo-mapeado-do-header-de-resposta" aria-label="Permalink to &quot;Passo 2: Pegue &quot;Conta + Modelo Mapeado&quot; do Header de Resposta&quot;">​</a></h3><p><strong>Por Que</strong> Para a mesma solicitação falhar/sucesso, muitas vezes depende de &quot;qual conta foi selecionada desta vez&quot;, &quot;para qual modelo upstream foi roteado&quot;. O proxy escreverá essas duas informações no header de resposta, primeiro anote, depois pode corresponder ao ver logs.</p><p>Naquela solicitação falhada, encontre esses headers de resposta:</p><ul><li><code>X-Account-Email</code></li><li><code>X-Mapped-Model</code></li></ul><p>Esses dois itens são definidos tanto no handler <code>/v1/messages</code> quanto no handler Gemini (por exemplo, na resposta SSE de <code>/v1/messages</code>: <code>src-tauri/src/proxy/handlers/claude.rs#L887-L896</code>; SSE Gemini: <code>src-tauri/src/proxy/handlers/gemini.rs#L235-L245</code>).</p><p><strong>Você Deve Ver</strong>: <code>X-Account-Email</code> é o email, <code>X-Mapped-Model</code> é o nome do modelo realmente solicitado.</p><h3 id="passo-3-em-app-log-determine-se-falhou-na-fase-peek" tabindex="-1">Passo 3: Em app.log Determine se &quot;Falhou na Fase Peek&quot; <a class="header-anchor" href="#passo-3-em-app-log-determine-se-falhou-na-fase-peek" aria-label="Permalink to &quot;Passo 3: Em app.log Determine se &quot;Falhou na Fase Peek&quot;&quot;">​</a></h3><p><strong>Por Que</strong> Falha de peek geralmente significa &quot;upstream realmente não começou a cuspir dados válidos&quot;. Tais problemas geralmente são tratados por retry/rotação de conta, você precisa confirmar se o proxy disparou.</p><p>Primeiro localize o arquivo de log (diretório de logs vem do diretório de dados <code>logs/</code>, e escreve em <code>app.log*</code> rolando por dia).</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-H9Wpy" id="tab--stOIJc" checked><label data-title="macOS/Linux" for="tab--stOIJc">macOS/Linux</label><input type="radio" name="group-H9Wpy" id="tab-q0aDXei"><label data-title="Windows" for="tab-q0aDXei">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Sort-Object</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LastWriteTime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Descending </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Select-Object</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">First </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div></div></div><p>Depois, no <code>app.log*</code> mais recente, pesquise estas palavras-chave:</p><ul><li><code>/v1/messages</code> (claude handler): <code>Stream error during peek</code> / <code>Stream ended during peek</code> / <code>Timeout waiting for first data</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L828-L864</code>)</li><li>Streaming nativo Gemini: <code>[Gemini] Empty first chunk received, retrying...</code> / <code>Stream error during peek</code> / <code>Stream ended immediately</code> (<code>src-tauri/src/proxy/handlers/gemini.rs#L117-L144</code>)</li></ul><p><strong>Você Deve Ver</strong>: Se peek retry foi disparado, o log aparecerá com alertas semelhantes a &quot;retrying...&quot;, e subsequentemente entrará na próxima tentativa (geralmente trará rotação de conta).</p><h3 id="passo-4-se-for-400-invalid-signature-confirme-se-o-proxy-fez-retry-de-reparo-de-assinatura" tabindex="-1">Passo 4: Se for 400/Invalid <code>signature</code>, Confirme se o Proxy Fez &quot;Retry de Reparo de Assinatura&quot; <a class="header-anchor" href="#passo-4-se-for-400-invalid-signature-confirme-se-o-proxy-fez-retry-de-reparo-de-assinatura" aria-label="Permalink to &quot;Passo 4: Se for 400/Invalid `signature`, Confirme se o Proxy Fez &quot;Retry de Reparo de Assinatura&quot;&quot;">​</a></h3><p><strong>Por Que</strong> Erros de assinatura frequentemente vêm de blocos Thinking/blocos de assinatura em mensagens históricas que não atendem aos requisitos upstream. O Antigravity Tools tentará &quot;degradar blocos thinking históricos + injetar prompt de reparo&quot; e depois retry, você deve primeiro deixar a autocura completar.</p><p>Você pode usar 2 sinais para determinar se entrou na lógica de reparo:</p><ol><li>Log aparece <code>Unexpected thinking signature error ... Retrying with all thinking blocks removed.</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L999-L1025</code>)</li><li>Posteriormente converterá blocos <code>Thinking</code> históricos em <code>Text</code>, e na última mensagem do usuário anexará o prompt de reparo (<code>src-tauri/src/proxy/handlers/claude.rs#L1027-L1102</code>; O handler Gemini também anexará o mesmo prompt em <code>contents[].parts</code>: <code>src-tauri/src/proxy/handlers/gemini.rs#L300-L325</code>)</li></ol><p><strong>Você Deve Ver</strong>: O proxy tentará retry automaticamente após um pequeno atraso (<code>FixedDelay</code>), e pode entrar na próxima tentativa.</p><h2 id="pontos-de-verificacao-✅" tabindex="-1">Pontos de Verificação ✅ <a class="header-anchor" href="#pontos-de-verificacao-✅" aria-label="Permalink to &quot;Pontos de Verificação ✅&quot;">​</a></h2><ul><li>[ ] Você pode confirmar no Proxy Monitor o caminho da solicitação (<code>/v1/messages</code> ou Gemini nativo)</li><li>[ ] Você pode obter o <code>X-Account-Email</code> e <code>X-Mapped-Model</code> desta solicitação</li><li>[ ] Você pode pesquisar palavras-chave relacionadas a peek/retry em <code>logs/app.log*</code></li><li>[ ] Ao encontrar erro de assinatura 400, você pode confirmar se o proxy entrou na lógica de retry &quot;prompt de reparo + limpar blocos thinking&quot;</li></ul><h2 id="lembrete-de-armadilhas" tabindex="-1">Lembrete de Armadilhas <a class="header-anchor" href="#lembrete-de-armadilhas" aria-label="Permalink to &quot;Lembrete de Armadilhas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cenário</th><th>O Que Você Pode Fazer (❌)</th><th>Recomendado (✓)</th></tr></thead><tbody><tr><td>Ver 0 Token e imediatamente tentar manualmente muitas vezes</td><td>Continuar pressionando o botão de retry do cliente, sem olhar o log</td><td>Primeiro olhe uma vez o Proxy Monitor + app.log, confirme se é morte prematura na fase peek (retry/rotação automática)</td></tr><tr><td>Encontrar <code>Invalid \\</code>signature`` e diretamente limpar diretório de dados</td><td>Deletar todo <code>.antigravity_tools</code>, contas/estatísticas tudo vai</td><td>Primeiro deixe o proxy executar uma vez &quot;retry de reparo de assinatura&quot;; só quando o log explicitamente dizer irreparável, considere intervenção manual</td></tr><tr><td>Tratar &quot;flutuação de servidor&quot; como &quot;conta quebrada&quot;</td><td>Rolar conta para todos 400/503/529</td><td>Se rotação é efetiva depende do código de status; o próprio proxy tem regras <code>should_rotate_account(...)</code> (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</td></tr></tbody></table><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><ul><li>0 Token/interrupção de streaming no proxy geralmente primeiro passa por peek pré-leitura; falha na fase peek disparará retry e entrará na próxima tentativa</li><li><code>/v1/messages</code> pode internamente converter solicitações não streaming em streaming e coletar de volta em JSON, isso afeta sua compreensão de &quot;por que parece problema de streaming&quot;</li><li>Para erros 400 de falha de assinatura, o proxy tentará &quot;prompt de reparo + limpar blocos thinking&quot; e depois retry, você priorize verificar se esse caminho de autocura passou</li></ul><h2 id="proximo-passo" tabindex="-1">Próximo Passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo Passo&quot;">​</a></h2><blockquote><p>Na próxima lição aprenderemos <strong><a href="./../../appendix/endpoints/">Tabela de Consulta Rápida de Endpoints</a></strong>.</p></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-fonte&quot;">​</a></h2><details><summary><strong>Clique para Expandir e Ver Localização do Código-fonte</strong></summary><blockquote><p>Última Atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Função</th><th>Caminho do Arquivo</th><th>Número da Linha</th></tr></thead><tbody><tr><td>Claude handler: estratégia de backoff retry + regras de rotação</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L117-L236" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>117-236</td></tr><tr><td>Claude handler: internamente converter não streaming em streaming (better quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L665-L776" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>665-776</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Claude handler: retry de reparo de erro de assinatura/ordem de bloco 400</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L999-L1102" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>999-1102</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Gemini handler: injeção de prompt de reparo de erro de assinatura 400</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/gemini.rs#L300-L325" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/gemini.rs</code></a></td><td>300-325</td></tr><tr><td>Cache de assinatura (três camadas: tool/family/session, com TTL/comprimento mínimo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/signature_cache.rs#L5-L207" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/signature_cache.rs</code></a></td><td>5-207</td></tr><tr><td>Conversão de SSE Claude: capturar assinatura e escrever no cache de assinatura</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/mappers/claude/streaming.rs#L639-L787" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/mappers/claude/streaming.rs</code></a></td><td>639-787</td></tr></tbody></table><p><strong>Constantes Chave</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: número máximo de retries (<code>src-tauri/src/proxy/handlers/claude.rs#L27</code>)</li><li><code>SIGNATURE_TTL = 2 * 60 * 60</code> segundos: TTL do cache de assinatura (<code>src-tauri/src/proxy/signature_cache.rs#L6</code>)</li><li><code>MIN_SIGNATURE_LENGTH = 50</code>: comprimento mínimo de assinatura (<code>src-tauri/src/proxy/signature_cache.rs#L7</code>)</li></ul><p><strong>Funções Chave</strong>:</p><ul><li><code>determine_retry_strategy(...)</code>: selecionar estratégia de backoff por código de status (<code>src-tauri/src/proxy/handlers/claude.rs#L117-L167</code>)</li><li><code>should_rotate_account(...)</code>: decidir se rolar conta por código de status (<code>src-tauri/src/proxy/handlers/claude.rs#L226-L236</code>)</li><li><code>SignatureCache::cache_session_signature(...)</code>: cachear assinatura de sessão (<code>src-tauri/src/proxy/signature_cache.rs#L149-L188</code>)</li></ul></details>',57)])])}const h=a(i,[["render",s]]);export{m as __pageData,h as default};
